let currentOwner = "";
let currentRepo = "";
let currentToken = "";

const statusDiv = document.getElementById("status");

function log(message) {
    statusDiv.textContent += "\n" + message;
    statusDiv.scrollTop = statusDiv.scrollHeight;
}

function parseRepo(url) {
    try {
        const u = new URL(url);

        if (u.hostname !== "github.com") {
            return null;
        }

        const parts = u.pathname
            .replace(/^\/+/, "")
            .replace(/\.git$/, "")
            .split("/");

        if (parts.length < 2) {
            return null;
        }

        return {
            owner: parts[0],
            repo: parts[1]
        };

    } catch (e) {
        return null;
    }
}

function fileToBase64(file) {
    return new Promise((resolve, reject) => {

        const reader = new FileReader();

        reader.onload = () => {
            resolve(reader.result.split(",")[1]);
        };

        reader.onerror = reject;

        reader.readAsDataURL(file);
    });
}

async function getFileSha(owner, repo, path, token) {

    try {

        const response = await fetch(
            `https://api.github.com/repos/${owner}/${repo}/contents/${path}`,
            {
                headers: {
                    Authorization: `Bearer ${token}`,
                    Accept: "application/vnd.github+json"
                }
            }
        );

        if (response.status === 200) {
            const data = await response.json();
            return data.sha;
        }

        return null;

    } catch {
        return null;
    }
}

async function deleteFolder(path = "") {

    const response = await fetch(
        `https://api.github.com/repos/${currentOwner}/${currentRepo}/contents/${path}`,
        {
            headers: {
                Authorization: `Bearer ${currentToken}`,
                Accept: "application/vnd.github+json"
            }
        }
    );

    if (!response.ok) {
        log(`❌ Cannot open ${path || "/"}`);
        return;
    }

    const items = await response.json();

    if (!Array.isArray(items)) {
        return;
    }

    for (const item of items) {

        if (item.type === "dir") {

            log(`📁 Folder: ${item.path}`);

            await deleteFolder(item.path);

        } else {

            log(`🗑️ Deleting: ${item.path}`);

            const delResponse = await fetch(
                `https://api.github.com/repos/${currentOwner}/${currentRepo}/contents/${item.path}`,
                {
                    method: "DELETE",
                    headers: {
                        Authorization: `Bearer ${currentToken}`,
                        Accept: "application/vnd.github+json",
                        "Content-Type": "application/json"
                    },
                    body: JSON.stringify({
                        message: `Delete ${item.path}`,
                        sha: item.sha
                    })
                }
            );

            if (delResponse.ok) {
                log(`✅ Deleted: ${item.path}`);
            } else {

                const err = await delResponse.json();

                log(`❌ Failed: ${item.path}`);
                log(`   ${err.message}`);
            }
        }
    }
}

/* ==========================
   Upload Button
========================== */

document.getElementById("uploadBtn")
.addEventListener("click", async () => {

    const repoUrl =
        document.getElementById("repoUrl")
        .value
        .trim();

    const token =
        document.getElementById("token")
        .value
        .trim();

    const files =
        document.getElementById("folderInput")
        .files;

    if (!repoUrl || !token || files.length === 0) {
        alert("Fill all fields and select folder.");
        return;
    }

    const repoInfo = parseRepo(repoUrl);

    if (!repoInfo) {
        alert("Invalid GitHub Repository URL.");
        return;
    }

    const { owner, repo } = repoInfo;

    currentOwner = owner;
    currentRepo = repo;
    currentToken = token;

    statusDiv.textContent = "";

    log(`🚀 Upload Started`);
    log(`📦 Repository: ${owner}/${repo}`);
    log(`📄 Total Files: ${files.length}`);

    let successCount = 0;
    let failCount = 0;

    for (const file of files) {

        let path = file.webkitRelativePath
            .split("/")
            .slice(1)
            .join("/");

        if (!path) {
            path = file.name;
        }

        const lower = path.toLowerCase();

        if (
            lower.includes(".ds_store") ||
            lower.includes("thumbs.db")
        ) {
            continue;
        }

        try {

            log(`📤 Uploading: ${path}`);

            const content =
                await fileToBase64(file);

            const sha =
                await getFileSha(
                    owner,
                    repo,
                    path,
                    token
                );

            const body = {
                message: `Upload ${path}`,
                content: content
            };

            if (sha) {
                body.sha = sha;
            }

            const response = await fetch(
                `https://api.github.com/repos/${owner}/${repo}/contents/${path}`,
                {
                    method: "PUT",
                    headers: {
                        Authorization: `Bearer ${token}`,
                        Accept: "application/vnd.github+json",
                        "Content-Type": "application/json"
                    },
                    body: JSON.stringify(body)
                }
            );

            if (response.ok) {

                successCount++;

                log(`✅ Uploaded: ${path}`);

            } else {

                failCount++;

                const err =
                    await response.json();

                log(`❌ Failed: ${path}`);
                log(`   ${err.message}`);
            }

        } catch (err) {

            failCount++;

            log(`❌ Error: ${path}`);
            log(`   ${err.message}`);
        }
    }

    log("");
    log(`✅ Success: ${successCount}`);
    log(`❌ Failed: ${failCount}`);
    log("🎉 Upload Complete");

});

/* ==========================
   Delete Button
========================== */

document.getElementById("deleteBtn")
.addEventListener("click", async () => {

    const repoUrl =
        document.getElementById("repoUrl")
        .value
        .trim();

    const token =
        document.getElementById("token")
        .value
        .trim();

    if (!repoUrl || !token) {
        alert("Repo URL aur Token dalo.");
        return;
    }

    const repoInfo = parseRepo(repoUrl);

    if (!repoInfo) {
        alert("Invalid Repo URL");
        return;
    }

    currentOwner = repoInfo.owner;
    currentRepo = repoInfo.repo;
    currentToken = token;

    if (!confirm(
        `Delete all files from ${currentOwner}/${currentRepo}?`
    )) {
        return;
    }

    statusDiv.textContent = "";

    log("🚀 Delete Started");

    try {

        await deleteFolder("");

        log("");
        log("🎉 Delete Complete");

    } catch (err) {

        log(`❌ ${err.message}`);
    }

});
